import React, { Component } from 'react';
import { Link, withRouter } from 'react-router-dom';
import { connect } from 'react-redux';
import PropTypes from 'prop-types';
import s from '../Auth.module.scss';
import $ from 'jquery';
import Icon from '../../../Icons/base';
import ReactLoading from 'react-loading';
import axios from 'axios';

class PasswordResetChange extends Component {

    constructor(props) {
        super(props);
        this.state = {
            new_password: "",
            repeated_password: "",
            waiting: false,
            token: null
        };        

        this.handleInputChange = this.handleInputChange.bind(this);
        this.submitForm = this.submitForm.bind(this);

        if (props.auth.isAuthenticated) {
            props.history.push('/');
        }
    }

    componentDidMount() {
        const { token } = this.props.match.params;

        axios.post(`${process.env.REACT_APP_GLOBAL_API_URL}/api/auth/password-recovery/request`, { token: token }).then(res => {
            console.log(res.data);

        })
    }

    handleInputChange(e) {
        const current_target = [e.target.name].toString();
        this.setState({ [e.target.name]: e.target.value, error_general: null });
    }

    triggerFocus(e) {
        $(e.target).parent().addClass(s['form-group--active']);
    }

    removeFocus(e) {
        if (e.target.value == "") {
            $(e.target).parent().removeClass(s['form-group--active']);
        }
    }

    submitForm(e) {
        e.preventDefault();
        this.setState({ waiting: true });
        axios.post(`${process.env.REACT_APP_GLOBAL_API_URL}/api/auth/password-recovery/request`, { email: this.state.email }).then(res => {
            if(res.data['status'] === undefined || res.data['status'] !== 1) {
                this.setState({ error_general: res.data['general'], waiting: false })
            } else {
                this.setState({ success: true, waiting: false });
            }
        })
    }

    render() {
        const { waiting, errors } = this.state;
        return (
            <div className={s.background}>
                <div className={s.form}>
                    <div className={s.header}>
                        <h3>Password change</h3>
                        <Link to="/">Artly</Link>
                    </div>
                    <form onSubmit={this.submitForm} autoComplete="none">
                        <div className={s['form-group']}>
                            <input
                                type="text"
                                name="login"
                                autoComplete="off"
                                onChange={this.handleInputChange}
                                onFocus={this.triggerFocus}
                                onBlur={this.removeFocus}
                                value={this.state.email}
                                className='bs-input'
                            />
                            <span>New password</span>
                            {(errors !== undefined && errors.new_password !== '') ? <p className={s['form-error']}>{errors.new_password}</p> : ''}
                        </div>
                        <div className={s['form-group']}>
                            <input
                                type="password"
                                name="password"
                                autoComplete="off"
                                onChange={this.handleInputChange}
                                onFocus={this.triggerFocus}
                                onBlur={this.removeFocus}
                                value={this.state.password}
                                className='bs-input'
                            />
                            <img src=""/>
                            <span>Confirm new password</span>
                            {(errors !== undefined && errors.repeated_password !== '') ? <p className={s['form-error']}>{errors.repeated_password}</p> : ''}
                            {(errors !== undefined && errors.general !== '') ? <p className={s['form-error']}>{errors.general}</p> : ''}
                        </div>
                        <div className={[s['form-group'], s['form-group__submit']].join(' ')}>
                            <button type="submit" disabled={this.state.waiting}>{waiting ? <ReactLoading type="bars" color="#ffffff" height="auto" width="auto" /> : "Change password"}</button>
                        </div>
                    </form>
                </div>
            </div>
        )
    }
}

PasswordResetChange.propTypes = {
    auth: PropTypes.object,
    history: PropTypes.object.isRequired
};

const mapStateToProps = (state) => ({
    auth: state.auth
});

export default withRouter(connect(mapStateToProps)(PasswordResetChange));


